package genxsolution.vms.vmsbackend.vehicle_management.vehicle_assignment.service;
import genxsolution.vms.vmsbackend.vehicle_management.exception.VehicleResourceNotFoundException; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_assignment.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_assignment.mapper.VehicleAssignmentMapper; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_assignment.repository.VehicleAssignmentRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleAssignmentService { private final VehicleAssignmentRepository repository; private final VehicleAssignmentMapper mapper; public VehicleAssignmentService(VehicleAssignmentRepository repository,VehicleAssignmentMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleAssignmentResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public VehicleAssignmentResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleAssignment", id.toString())); } public VehicleAssignmentResponse create(VehicleAssignmentUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleAssignmentResponse update(UUID id,VehicleAssignmentUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleAssignment", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new VehicleResourceNotFoundException("VehicleAssignment", id.toString()); } }
